import React, { useState, useEffect } from "react";
import "../styles/booking.css"; // create this file (CSS below)

export default function Booking({ rooms = [] }) {
  // form state
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    room_id: rooms.length > 0 ? rooms[0].id || rooms[0].room_id : "", // default room if provided
    adults: 1,
    children: 0,
    checkin: "",
    checkout: "",
    notes: "",
  });

  const [submitting, setSubmitting] = useState(false);
  const [message, setMessage] = useState(null); // { type: 'success'|'error', text: '' }

  // keep form.room_id updated if rooms prop changes
  useEffect(() => {
    if (!form.room_id && rooms.length > 0) {
      setForm((f) => ({ ...f, room_id: rooms[0].id || rooms[0].room_id }));
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [rooms]);

  // basic client-side validation
  const validate = () => {
    const { name, email, checkin, checkout, adults } = form;
    if (!name.trim()) return "Please enter your name.";
    if (!email.trim() || !/^\S+@\S+\.\S+$/.test(email)) return "Please enter a valid email.";
    if (!checkin) return "Please choose a check-in date.";
    if (!checkout) return "Please choose a check-out date.";
    if (new Date(checkout) <= new Date(checkin)) return "Check-out must be after check-in.";
    if (Number(adults) < 1) return "Please select number of adults.";
    return null;
  };

  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
  };

  const submitHandler = async (e) => {
    e.preventDefault();
    setMessage(null);

    const err = validate();
    if (err) {
      setMessage({ type: "error", text: err });
      return;
    }

    setSubmitting(true);

    try {
      // NOTE: change this URL to your real backend endpoint when ready
      const resp = await fetch("http://127.0.0.1:8000/api/reservations/", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });

      if (!resp.ok) {
        const errBody = await resp.json().catch(() => null);
        throw new Error(errBody?.detail || `Server error (${resp.status})`);
      }

      const data = await resp.json();
      setMessage({ type: "success", text: "Reservation successful! Reference: " + (data.id || data.reference || "") });
      // optionally reset form
      setForm({
        name: "",
        email: "",
        phone: "",
        room_id: rooms.length > 0 ? rooms[0].id || rooms[0].room_id : "",
        adults: 1,
        children: 0,
        checkin: "",
        checkout: "",
        notes: "",
      });
    } catch (err) {
      setMessage({ type: "error", text: err.message || "Failed to submit reservation." });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="booking-wrap">
      <h2>Make a Reservation</h2>

      {message && (
        <div className={`notify ${message.type === "success" ? "ok" : "err"}`}>
          {message.text}
        </div>
      )}

      <form className="booking-form" onSubmit={submitHandler} noValidate>
        <div className="row">
          <label>
            Full name
            <input name="name" value={form.name} onChange={onChange} placeholder="Your full name" />
          </label>

          <label>
            Email
            <input name="email" value={form.email} onChange={onChange} placeholder="you@example.com" />
          </label>
        </div>

        <div className="row">
          <label>
            Phone
            <input name="phone" value={form.phone} onChange={onChange} placeholder="+91 9xxxxxxxxx" />
          </label>

          <label>
            Room
            <select name="room_id" value={form.room_id} onChange={onChange}>
              {rooms.length > 0 ? (
                rooms.map((r) => (
                  <option key={r.id || r.room_id} value={r.id || r.room_id}>
                    {r.room_name || r.name} — ₹{Number(r.price || r.rate || 0).toFixed(2)}
                  </option>
                ))
              ) : (
                <option value="">(No room list)</option>
              )}
            </select>
          </label>
        </div>

        <div className="row">
          <label>
            Check-in
            <input name="checkin" type="date" value={form.checkin} onChange={onChange} />
          </label>

          <label>
            Check-out
            <input name="checkout" type="date" value={form.checkout} onChange={onChange} />
          </label>
        </div>

        <div className="row">
          <label>
            Adults
            <input name="adults" type="number" min="1" value={form.adults} onChange={onChange} />
          </label>

          <label>
            Children
            <input name="children" type="number" min="0" value={form.children} onChange={onChange} />
          </label>
        </div>

        <label>
          Notes (optional)
          <textarea name="notes" value={form.notes} onChange={onChange} placeholder="Any requests (late check-in, food preferences)" />
        </label>

        <div className="form-actions">
          <button type="submit" className="btn" disabled={submitting}>
            {submitting ? "Submitting…" : "Book Now"}
          </button>
        </div>
      </form>
    </div>
  );
}
